module serial2parallel(
    input clk, input rst_n, input din_serial, input din_valid,
    output reg [7:0] dout_parallel, output reg dout_valid
);
    reg [3:0] cnt;
    reg [7:0] temp_data;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'b0000;
            temp_data <= 8'b0;
            dout_parallel <= 8'b0;
            dout_valid <= 1'b0;
        end else begin
            if (din_valid) begin
                temp_data <= {temp_data[6:0], din_serial};
                cnt <= cnt + 4'b0001;
                if (cnt == 4'b1000) begin
                    dout_parallel <= temp_data;
                    dout_valid <= 1'b1;
                end else begin
                    dout_valid <= 1'b0;
                end
            end else begin
                dout_valid <= 1'b0;
            end
        end
    end
endmodule
